+    JointInfo* EffortDisplay::getJointInfo( const std::string& joint)
+    {
+        M_JointInfo::iterator it = joints_.find( joint );
+        if ( it == joints_.end() )
+            {
+                return NULL;
+            }
+
+        return it->second;
+    }
