+, alpha_property_( NULL )
+{
+  scene_node_ = scene_manager_->getRootSceneNode()->createChildSceneNode();
+
+  static int count = 0;
+  std::stringstream ss;
+  ss << "PolyLine2D" << count++;
+  manual_object_ = scene_manager_->createManualObject( ss.str() );
+  manual_object_->setDynamic( true );
