+DisplayInfo* VisualizationManager::getDisplayInfo( const Display* display )
+{
+  V_DisplayInfo::iterator vis_it = displays_.begin();
+  V_DisplayInfo::iterator vis_end = displays_.end();
+  for ( ; vis_it != vis_end; ++vis_it )
